<div class="stats-grid"><div class="stat-card primary"><span>Total Credits</span><h2><?= money((float)$totals['credit']) ?></h2></div><div class="stat-card"><span>Total Debits</span><h2><?= money((float)$totals['debit']) ?></h2></div></div><div class="card section-gap"><div class="card-head"><h3>30-Day Summary</h3></div><div class="table-wrap"><table><thead><tr><th>Date</th><th>Transaction Count</th><th>Total Amount</th></tr></thead><tbody><?php foreach ($dailySummary as $day): ?><tr><td><?= e($day['day']) ?></td><td><?= (int)$day['total_count'] ?></td><td><?= money((float)$day['total_amount']) ?></td></tr><?php endforeach; ?><?php if (!$dailySummary): ?><tr><td colspan="3">No report data available.</td></tr><?php endif; ?></tbody></table></div></div>
